import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";

const duckImg = "data:image/png;base64,";
const leftBubbleImg = "data:image/png;base64,";
const rightBubbleImg = "data:image/png;base64,";
const ellipseImg = "data:image/png;base64,";
const volumeXImg = "data:image/png;base64,";

// Load Ranchers font
const fontLink = document.createElement("link");
fontLink.rel = "stylesheet";
fontLink.href = "https://fonts.googleapis.com/css2?family=Ranchers&display=swap";
document.head.appendChild(fontLink);

export default function TitlePage() {
  const [duckHovered, setDuckHovered] = useState(false);
  const [soundOn, setSoundOn] = useState(true);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const t = setTimeout(() => setVisible(true), 80);
    return () => clearTimeout(t);
  }, []);

  const navigate = useNavigate();

  const handleDuckClick = () => {
    navigate("/get-started");
  };

  return (
    <div
      style={{
        position: "relative",
        width: "100vw",
        height: "100vh",
        background: "#2d0f3f",
        overflow: "hidden",
        fontFamily: "'Ranchers', cursive",
        opacity: visible ? 1 : 0,
        transition: "opacity 0.6s ease",
      }}
    >
      {/* Sound button */}
      <button
        onClick={() => setSoundOn(s => !s)}
        style={{
          position: "absolute",
          top: 20,
          right: 20,
          width: 56,
          height: 56,
          borderRadius: "50%",
          background: "none",
          border: "none",
          cursor: "pointer",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          padding: 0,
          zIndex: 10,
          transition: "transform 0.1s ease",
        }}
        onMouseEnter={e => e.currentTarget.style.transform = "scale(1.1)"}
        onMouseLeave={e => e.currentTarget.style.transform = "scale(1)"}
      >
        {/* Background circle — cream when on, red ellipse when off */}
        {soundOn ? (
          <div style={{
            position: "absolute",
            inset: 0,
            borderRadius: "50%",
            background: "#fffff0",
            boxShadow: "0 2px 8px rgba(0,0,0,0.3)",
          }} />
        ) : (
          <img src={ellipseImg} alt="" style={{ position: "absolute", inset: 0, width: "100%", height: "100%", borderRadius: "50%" }} />
        )}

        {/* Icon — speaker waves when on, volume-x when off */}
        <div style={{ position: "relative", zIndex: 1 }}>
          {soundOn ? (
            <svg width="26" height="26" viewBox="0 0 24 24" fill="none" stroke="#222" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5" />
              <path d="M19.07 4.93a10 10 0 0 1 0 14.14" />
              <path d="M15.54 8.46a5 5 0 0 1 0 7.07" />
            </svg>
          ) : (
            <img src={volumeXImg} alt="Muted" style={{ width: 26, height: 26, display: "block" }} />
          )}
        </div>
      </button>

      {/* Left speech bubble */}
      <div
        style={{
          position: "absolute",
          top: "8%",
          left: "3%",
          width: "30%",
          maxWidth: 380,
        }}
      >
        <div style={{ position: "relative" }}>
          <img src={leftBubbleImg} alt="" style={{ width: "100%", display: "block" }} />
          <div
            style={{
              position: "absolute",
              top: "10%",
              left: "10%",
              right: "10%",
              bottom: "20%",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
            }}
          >
            <span
              style={{
                fontFamily: "'Ranchers', cursive",
                fontSize: "clamp(16px, 2.6vw, 50px)",
                color: "#111",
                textAlign: "center",
                lineHeight: 1.2,
                fontWeight: "bold",
              }}
            >
              New to college life?
            </span>
          </div>
        </div>
      </div>

      {/* Duck - centered */}
      <div
        style={{
          position: "absolute",
          left: "50%",
          top: "50%",
          transform: `translate(-50%, -50%) scale(${duckHovered ? 1.05 : 1})`,
          transition: "transform 0.15s ease",
          width: "clamp(200px, 35vw, 420px)",
          cursor: "pointer",
          zIndex: 2,
        }}
        onClick={handleDuckClick}
        onMouseEnter={() => setDuckHovered(true)}
        onMouseLeave={() => setDuckHovered(false)}
      >
        <img
          src={duckImg}
          alt="Cool duck mascot"
          style={{
            width: "100%",
            display: "block",
            filter: "drop-shadow(0 12px 32px rgba(0,0,0,0.5))",
          }}
        />
      </div>

      {/* Right speech bubble */}
      <div
        style={{
          position: "absolute",
          top: "38%",
          right: "3%",
          width: "26%",
          maxWidth: 320,
        }}
      >
        <div style={{ position: "relative" }}>
          <img src={rightBubbleImg} alt="" style={{ width: "100%", display: "block" }} />
          <div
            style={{
              position: "absolute",
              top: "8%",
              left: "10%",
              right: "8%",
              bottom: "18%",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
            }}
          >
            <span
              style={{
                fontFamily: "'Ranchers', cursive",
                fontSize: "clamp(14px, 2.3vw, 45px)",
                color: "#111",
                textAlign: "center",
                lineHeight: 1.2,
                fontWeight: "bold",
              }}
            >
              Wanna find the perfect club?
            </span>
          </div>
        </div>
      </div>

      {/* Bottom label */}
      <div
        style={{
          position: "absolute",
          bottom: "6%",
          left: "50%",
          transform: "translateX(-50%)",
          fontFamily: "'Ranchers', cursive",
          fontSize: "clamp(28px, 5.5vw, 80px)",
          color: "#fff",
          whiteSpace: "nowrap",
          letterSpacing: "0.02em",
          textShadow: "0 2px 16px rgba(0,0,0,0.4)",
          userSelect: "none",
          pointerEvents: "none",
        }}
      >
        Click me to get started !
      </div>
    </div>
  );
}
